var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"팔다리를 모두 잘랐다. 이 정도로 죽지 않는다는 걸 잘 알고 있어.","JPN":"手足を切り落としたぞ。この程度では死なないことはわかっている。","ENG":"All your limbs have been cut. I know that this won't kill you.","TWN":"我砍斷了你的手腳，我知道你這樣不會死。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"쉽게 도망칠 생각은 하지 마라.","JPN":"簡単に逃げられるとは思うな。","ENG":"Don't you think about running away.","TWN":"別想輕易逃跑。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"켁…… 킥킥…….","JPN":"くすっ……くすくす！","ENG":"Ke... keke...","TWN":"咳…… 呵呵……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"남을 흉내 내는 가짜 주제에 기분 나쁘게 웃는군.","JPN":"誰かの模倣品のくせに、気持ち悪い笑い方だな。","ENG":"You laugh terribly for imitating someone.","TWN":"你這個冒牌貨，居然還笑得那麼噁心。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"어차피 내가 누굴 흉내 내는지 모를 거 아냐? 원본이 정말 이렇게 웃을 수도 있지.","JPN":"どうせ私が誰のマネをしているか、知らないんでしょ？　オリジナルがこんなふうに笑うかどうか、お前にはわからない。","ENG":"You don't even know who I'm imitating. Maybe the original also laughs like this.","TWN":"反正你也不知道我在模仿誰吧？要是本體也是這麼笑的呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"아하하. 너무 그렇게 인상 쓰지 마.","JPN":"あはは、そんなに怖い顔しないでよ。","ENG":"Ah hah hah. Don't look so grim.","TWN":"呵呵呵，別那樣皺著眉頭。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"<color=#ffd34c>우리</color>도 원본을 차지하지 못하는 게 참 거지 같거든.","JPN":"<color=#ffd34c>私たち</color>もオリジナルを吸収できなくて、不愉快極まりないんだから。","ENG":"<color=#ffd34c>We</color> are also irritated that we can't catch the original yet.","TWN":"<color=#ffd34c>我們</color>也沒能抓到本體，感覺真差。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"어떻게 보면 우리 모두 원하는 것을 손에 넣을 수 없다는 점이 같지 않아?","JPN":"ほしいものが手に入らないという点では、お互い一緒だよね？","ENG":"In some ways, aren't we the same in that we both can't get what we want?","TWN":"從某種角度來看，我們都無法得到自己想要的東西，不是嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"원본을 차지하지 못한다고?","JPN":"オリジナルが手に入らない？","ENG":"You can't catch the original?","TWN":"無法抓到本體嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"누군가 원본을 차지하고 있나?","JPN":"もう誰かの手に渡ってしまったというのか？","ENG":"Then does someone else have her?","TWN":"她在誰的手裡？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"너도 알다시피. 어떤 미친 고래가 원본을 차지하고 있지.","JPN":"お前も知っているでしょう。あのイカレたクジラだよ。","ENG":"As you know, that crazy whale has taken the original.","TWN":"你見過的，是那條發瘋的鯨魚。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"원본을 가질 수 없게 된 우리가 선택한 건, 기억 속에서 느껴지는 강한 집착을 해소하는 것.","JPN":"オリジナルを吸収できない私たちが選んだのは、記憶に残っている強い執着の解消だった。","ENG":"And what we chose was to relieve the strong obsession we feel within our memories because the original is unobtainable.","TWN":"無法吸收本體的我們，選擇消解記憶中那強烈的執念。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"너한테 이토록 강한 집착이 느껴지는 건…… 그만큼 네가 원본에게 소중한 사람이란 뜻이겠지?","JPN":"お前に対してこんなにも強い執着が感じられるのは……オリジナルにとってお前はものすごく大切な存在だということ。","ENG":"And the reason why we're feeling a strong obsession to you is... probably because you are someone precious to the original, no?","TWN":"我們會對你如此地執著……這表示你對本體來說是個重要的人吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"참 죄 많은 여자네. 침식체와 침식체가 되었을지도 모를 여자의 관심을 받고 있다니.","JPN":"罪深き女ね。侵食体と侵食体になったかもしれない女から想いを寄せられているなんて。","ENG":"What a sinful woman. Getting the attention of both the C.O. and a girl who may or may not have become a C.O.","TWN":"真是個罪孽深重的女人，竟然得到那麼多人的關心。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그들이 나에게 관심을 갖고 있는 이유를 알고 있나?","JPN":"どうして彼らが私に興味を持っているのか、理由を知っているか？","ENG":"Do you know why they are interested in me?","TWN":"為什麼會對我感興趣？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"글쎄. 네가 원본을 대신 제공해준다면 말해줄 의향이 있는데?","JPN":"さあね、お前が代わりにオリジナルを差し出してくれるなら、教えてやってもいいけど？","ENG":"Well, I'm willing to answer that question if you provide the original for us instead.","TWN":"不告訴你。如果你能給我本體的話，我倒是願意告訴你。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그럼 협상 결렬이군. 끝이다. 도플갱어.","JPN":"交渉は決裂だな。もうおしまいだ、ドッペルゲンガー。","ENG":"Then we have nothing to talk about. No deal, Doppelganger.","TWN":"談判破裂。去死吧，二重身。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"내 나름대로 협상안을 제시했던 건데, 아쉽게 됐어.","JPN":"私はそれなりにいい提案をしたつもりだけど、残念だね。","ENG":"What a shame. It was the best offer that I could suggest.","TWN":"真是遺憾，我還以為是個不錯的提議。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"아, 그 침식체는 어떻게든 너를 흡수해서 <color=#ffd34c>우리들의 태양</color>으로 만든다더라?","JPN":"あ、ちなみに、その侵食体はなんとしてでもお前を吸収し、<color=#ffd34c>自分たちの太陽</color>にするって言ってたよ？","ENG":"Oh, and by the way, that C.O. is going to absorb you and make you into <color=#ffd34c>our sun</color>. Did you know that?","TWN":"對了，那個侵蝕體無論如何都會吸收你，把你變成<color=#ffd34c>我們的太陽</color>喔？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"그게 운명이라나 뭐라나. 아하하.","JPN":"それが運命だとかなんとか。あはは。","ENG":"Something about fate or whatnot. Ah hah hah.","TWN":"這就是所謂的命運吧，呵呵呵。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"자기가 완전해지기 위해선 당신이 필요하다 그러더군.","JPN":"自分が完全になるためにお前が必要だそうだ。","ENG":"It said that it needed you to become complete.","TWN":"它說需要你來讓它變得完整。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"걘 아직도 자기가 사람인 줄 알더라고.","JPN":"やつはまだ自分が人間だと思っている。","ENG":"Guess it still thinks it's human.","TWN":"還以為自己是個人呢……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"나는 그냥 본능대로 원본만 꿀꺽하고 싶을 뿐이야.","JPN":"私は本能に従って、オリジナルを吸収したいだけさ。","ENG":"For me, I just want to follow my instincts and take just the original.","TWN":"而我，我只是想順著本能吞噬掉本體而已。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"갈 곳 잃은 들개처럼 여기저기 들쑤시는 게 아니라.","JPN":"あてもなく彷徨い、手当たり次第かき乱すんじゃなく。","ENG":"And not wander around like a lost dog everywhere.","TWN":"不再做一條迷失亂竄的野狗。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"그러니까…… 나 같은 도플갱어들에겐 더 이상 살아갈 이유가 없다는 거지.","JPN":"だから……私のようなドッペルゲンガーにもう生きる理由はないということ。","ENG":"What I'm trying to say is... that Doppelgangers like me have no reason to live anymore.","TWN":"所以……像我這樣的二重身已經沒有繼續活下去的理由了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK_02"},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"스스로 핵을 파괴하다니!","JPN":"自ら核を破壊したのか！？","ENG":"Did you just destroy your core?!","TWN":"你居然自己破壞核心！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"침식체한테 상식을 바란 건 아니지? 난 할 얘기 다 해줬다?","JPN":"侵食体に常識を求めているわけじゃないでしょう？　私はすべて話したよ？","ENG":"You're not expecting common sense from a C.O., are you? Anyway, I've told you everything I know, okay?","TWN":"你不會指望侵蝕體有常識吧？我可是該說的都說了？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"인간들도 정보 불기 싫다고 자기 혀를 깨물고 그러잖아?","JPN":"人間も情報を隠すために、自分の舌を噛んだりするんじゃない？","ENG":"I mean, even humans would rather bite their tongue off rather than spill the beans, no?","TWN":"人類也會因為不想洩密而咬舌自盡，不是嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"원본을 흡수하지도 못하는데 굳이 남아 있을 필요는 없지.","JPN":"オリジナルを吸収することもできないのに、残る意味はない。","ENG":"If I can't absorb my original, there really isn't a reason for me to stick around.","TWN":"而我，既然無法吸收本體，還有什麼存在的意義呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"어디 구멍 숭숭 난 뇌로 고래랑 잘 싸워 보라고~","JPN":"その穴だらけの脳みそで、せいぜいクジラとの戦いでも頑張れよ～","ENG":"Well, good luck trying to fight that whale with your half-empty brain.","TWN":"用你那千瘡百孔的腦袋去和鯨魚好好打一架吧～"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나를 흡수하고 우리들의 태양으로 만든다고?","JPN":"私を吸収し、自分たちの太陽にするだと？","ENG":"Absorb me to make me their sun?","TWN":"吸收我，成為我們的太陽？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"과거에 나와 무슨 일이 있었던 거냐, 침식체.","JPN":"過去に私といったい何があった、侵食体。","ENG":"What happened between you and me in the past, C.O.?","TWN":"過去你和我到底發生過什麼事，侵蝕體？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나를 흡수하기 위해서, 이런 일들을 벌여 왔다는 건가?","JPN":"私を吸収するために、今までのことを引き起こしているというのか？","ENG":"You caused all this just so you can absorb me?","TWN":"為了吸收我，才會做出這些事嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"확신할 수 있는 건 아무것도 없다.","JPN":"確かなものは何一つない。","ENG":"There is nothing I can be certain about.","TWN":"好像霧裡看花，充滿謎團。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"모든 의문을 풀기 위해선 그 고래를 다시 만나야 해.","JPN":"すべてを明らかにするためには、あのクジラにもう一度会わなければならない。","ENG":"I must meet that whale again to resolve everything.","TWN":"要揭開所有疑問，就必須再見到那隻鯨魚。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};